import json

baseline = json.load(open('baseline-packages-local.json'))
after = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (pname, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
all_keys = sorted(set(b.keys()) | set(a.keys()))
for k in all_keys:
    proj, tfm, pkg = k
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        if bv == 'N/A':
            changes.append((proj, tfm, pkg, bv, av, 'Added'))
        elif av == 'N/A':
            changes.append((proj, tfm, pkg, bv, av, 'Removed'))
        else:
            changes.append((proj, tfm, pkg, bv, av, 'Aligned to highest version'))
    else:
        unchanged.append((proj, tfm, pkg, av))

print('=== CHANGES ===')
if changes:
    print(f'{'Project':<16} {'TFM':<8} {'Package':<45} {'Before':<10} {'After':<10} Status')
    for c in changes:
        print(f'{c[0]:<16} {c[1]:<8} {c[2]:<45} {c[3]:<10} {c[4]:<10} {c[5]}')
else:
    print('No changes')

print()
print('=== UNCHANGED ===')
print(f'{'Project':<16} {'TFM':<8} {'Package':<45} {'Version':<10}')
for u in unchanged:
    print(f'{u[0]:<16} {u[1]:<8} {u[2]:<45} {u[3]:<10}')
"

